function getKanjiByGrade(g){return KANJI_DATA.filter(function(k){return k.grade===g;});}
function getRandomKanji(g,n){n=n||10;var p=getKanjiByGrade(g).slice().sort(function(){return Math.random()-0.5;});return p.slice(0,Math.min(n,p.length));}
